const events = $input.all();
const results = [];

for (const item of events) {
  const event = item.json;

  if (!event.summary?.includes('Growth AI - Automatisons vos tâches')) continue;

  for (const attendee of event.attendees || []) {
    if (['user@example.com', 'user@example.com'].includes(attendee.email)) continue;

    results.push({ json: { email: attendee.email } });
  }
}

return results;
